// Read the live projections, find districts projected into the HIGH band,
// and compose one WhatsApp alert. Threshold: band_sep === 'High' (score >= 66, per engine.py).
const raw = $('Fetch Projections').item.json.data || '';
function unwrap(r, marker){ const i = r.indexOf(marker); if(i<0) throw new Error('no marker'); let s = r.slice(i+marker.length).trim(); s = s.replace(/;+\s*$/, ''); return JSON.parse(s); }
let proj = null;
try { proj = unwrap(raw, 'window.HOZI='); } catch(e){}
if(!proj){ return [{ json: { highCount: 0 } }]; }

const APP = 'https://nash1987poli.github.io/hozi/';
const date = new Date().toISOString().slice(0,10);
const high = (proj.watch || []).filter(d => d.band_sep === 'High');
if(high.length === 0){ return [{ json: { highCount: 0 } }]; }

const top = high.slice(0, 8).map(d => `• *${d.district}* — ${Math.round(d.projected_sep)} by Sep  ${APP}?district=${encodeURIComponent(d.district)}`).join('\n');
const natl = (proj.national && proj.national.risk_sep != null) ? proj.national.risk_sep : 'n/a';
const body = `⚠️ *HOZI ALERT — ${date}*\n*${high.length} districts* projected *HIGH* food-security risk by September (score \u2265 66):\n\n${top}\n\nNational projected Sep risk: *${natl}*.\nAct before the July window opens — grain and transfers take 25\u201360 days.\n📍 Full map & Response Planner: ${APP}\n\n_Automated Layer-0 alert. In the pilot each officer receives only their own district._`;

const to = ($env && $env.HOZI_OFFICER_NUMBER) ? $env.HOZI_OFFICER_NUMBER : 'OFFICER_WHATSAPP_NUMBER_PLACEHOLDER';
return [{ json: { highCount: high.length, to, body } }];
